      },
      {
        "minutes": 20,
        "topic": "தமிழ்விடு தூது: கதைக்களம் மற்றும் பாடல் வரிகள்",
        "teachingStrategy": "படிப்பு, விவாதம் மற்றும் சந்தப் பாராயணம்"
      },
      {
        "minutes": 5,
        "topic": "முடிவுரை மற்றும் மதிப்பீடு",
        "teachingStrategy": "சுருக்கமான கேள்வி-பதில் வட்டம்"
      }
